void Application::SetAecMode(AecMode mode)
{
    aec_mode_ = mode;
    Schedule([this]()
             {
        auto& board = Board::GetInstance();
        auto display = board.GetDisplay();
        switch (aec_mode_) {
        case kAecOff:
            audio_service_.EnableDeviceAec(false);
            display->ShowNotification(Lang::Strings::RTC_MODE_OFF);
            break;
        case kAecOnServerSide:
            audio_service_.EnableDeviceAec(false);
            display->ShowNotification(Lang::Strings::RTC_MODE_ON);
            break;
        case kAecOnDeviceSide:
            audio_service_.EnableDeviceAec(true);
            display->ShowNotification(Lang::Strings::RTC_MODE_ON);
            break;
        }

        // If the AEC mode is changed, close the audio channel
        if (protocol_ && protocol_->IsAudioChannelOpened()) {
            protocol_->CloseAudioChannel();
        } });
}

bool Assets::InitializePartition()
{
    // Find the assets partition
    partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_SPIFFS, "assets");
    if (partition_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to find assets partition");
        return false;
    }

    // Check if partition is valid
    if (partition_->size == 0)
    {
        ESP_LOGE(TAG, "Assets partition size is zero");
        return false;
    }

    // Map the partition into memory
    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, ESP_PARTITION_MMAP_DATA, (const void **)&mmap_root_, &mmap_handle_);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        return false;
    }

    // Validate partition header
    if (mmap_root_[0] != 'A' || mmap_root_[1] != 'S' || mmap_root_[2] != 'S' || mmap_root_[3] != 'E')
    {
        ESP_LOGE(TAG, "Assets partition has invalid magic number");
        return false;
    }

    // Get the number of assets from the header
    uint32_t asset_count = *(uint32_t *)(mmap_root_ + 4);

    // Build the asset index
    assets_.clear();
    const char *current_ptr = mmap_root_ + 8;  // Skip magic and count

    for (uint32_t i = 0; i < asset_count; i++)
    {
        struct mmap_assets_table *asset_entry = (struct mmap_assets_table *)current_ptr;

        // Validate asset entry
        if (asset_entry->asset_size == 0)
        {
            ESP_LOGW(TAG, "Skipping empty asset entry at index %u", i);
            current_ptr += sizeof(struct mmap_assets_table);
            continue;
        }

        // Create asset entry in our map
        AssetInfo info;
        info.size = asset_entry->asset_size;
        info.offset = asset_entry->asset_offset;
        info.width = asset_entry->asset_width;
        info.height = asset_entry->asset_height;

        // Copy asset name (ensure null termination)
        char name[33] = {0};
        memcpy(name, asset_entry->asset_name, sizeof(asset_entry->asset_name));
        name[32] = '\0';  // Ensure null termination

        assets_[std::string(name)] = info;

        // Move to next entry
        current_ptr += sizeof(struct mmap_assets_table);
    }

    // Validate checksum if present
    if (asset_count > 0)
    {
        uint32_t calculated_checksum = CalculateChecksum(mmap_root_ + 8, current_ptr - (mmap_root_ + 8));
        uint32_t stored_checksum = *(uint32_t *)(current_ptr);

        if (calculated_checksum != stored_checksum)
        {
            ESP_LOGE(TAG, "Assets partition checksum mismatch: calculated=0x%04X, stored=0x%04X", calculated_checksum, stored_checksum);
            return false;
        }
    }

    ESP_LOGI(TAG, "Assets partition initialized successfully with %u assets", asset_count);
    return true;
}

