            [2] = CAM_PIN_D2,
            [3] = CAM_PIN_D3,
            [4] = CAM_PIN_D4,
            [5] = CAM_PIN_D5,
            [6] = CAM_PIN_D6,
            [7] = CAM_PIN_D7,
        },
    };

    static esp_cam_ctlr_sccb_config_t sccb_config = {
        .i2c_port = I2C_NUM_0,
        .sda_io_num = CAMERA_SDA_PIN,
        .scl_io_num = CAMERA_SCL_PIN,
        .clk_speed_hz = 100000,
