        .pin_config = &dvp_pin_config,
        .sccb_config = &sccb_config,
        .frame_size = ESP_CAM_FRAME_SIZE_QVGA,
        .pixel_format = ESP_CAM_PIXEL_FORMAT_YUV422,
        .jpeg_quality = 10,
        .buffer_size = 1024 * 1024,
        .dma_frame_buffer_count = 2,
    };

    camera_ = new Esp32Camera(&cam_config);
    camera_->Initialize();
}

