        display->ClearScreen();
    }
}

std::vector<float> AudioSignalProcessor::ProcessAudioSamples(const std::vector<float> &samples)
{
    std::vector<float> probabilities;

    // Process samples in chunks of input_buffer_size_
    for (size_t i = 0; i < samples.size(); i += input_buffer_size_)
    {
        // Ensure we have enough samples for a complete window
        if (i + input_buffer_size_ > samples.size())
        {
            break;
        }

        // Reset detectors for new window
        mark_detector_->Reset();
        space_detector_->Reset();

        // Process all samples in the current window
        for (size_t j = 0; j < input_buffer_size_; ++j)
        {
            float sample = samples[i + j];
            mark_detector_->ProcessSample(sample);
            space_detector_->ProcessSample(sample);
        }

        // Get amplitudes from both detectors
        float mark_amplitude = mark_detector_->GetAmplitude();
        float space_amplitude = space_detector_->GetAmplitude();

        // Calculate probability: if mark amplitude is significantly higher than space amplitude,
        // it's likely a mark tone (probability close to 1.0)
        // if space amplitude is higher, it's likely a space tone (probability close to 0.0)
        float probability = 0.0f;
        if (mark_amplitude + space_amplitude > 0.0f)
        {
            probability = mark_amplitude / (mark_amplitude + space_amplitude);
        }

        probabilities.push_back(probability);
    }

    return probabilities;
}

bool AudioDataBuffer::ProcessProbabilityData(const std::vector<float> &probabilities, float threshold)
{
    for (float probability : probabilities)
    {
        // Convert probability to bit (0 or 1) based on threshold
        uint8_t bit = (probability > threshold) ? 1 : 0;

        // Add bit to identifier buffer
        identifier_buffer_.push_back(bit);

        // Keep identifier buffer size within bounds
        if (identifier_buffer_.size() > identifier_buffer_size_)
        {
            identifier_buffer_.pop_front();
        }

        // Check if we're in inactive state
        if (current_state_ == DataReceptionState::kInactive)
        {
            // Look for start transmission pattern
            if (identifier_buffer_.size() >= start_of_transmission_.size())
            {
                bool start_match = true;
                for (size_t i = 0; i < start_of_transmission_.size(); ++i)
                {
                    if (identifier_buffer_[identifier_buffer_.size() - start_of_transmission_.size() + i] != start_of_transmission_[i])
                    {
                        start_match = false;
                        break;
                    }
                }

                if (start_match)
                {
                    current_state_ = DataReceptionState::kWaitingForData;
                    ClearBuffers(); // Clear previous data
                }
            }
        }
        else if (current_state_ == DataReceptionState::kWaitingForData)
        {
            // We're waiting for data, so just add bits to the buffer
            bit_buffer_.push_back(bit);

            // Check if we've reached maximum buffer size
            if (bit_buffer_.size() >= max_bit_buffer_size_)
            {
                current_state_ = DataReceptionState::kInactive;
                return false; // Buffer overflow
            }
        }
        else if (current_state_ == DataReceptionState::kReceivingData)
        {
            // We're already receiving data, so just add bits to the buffer
            bit_buffer_.push_back(bit);

            // Check if we've reached maximum buffer size
            if (bit_buffer_.size() >= max_bit_buffer_size_)
            {
                current_state_ = DataReceptionState::kInactive;
                return false; // Buffer overflow
            }
        }

        // Check for end transmission pattern
        if (identifier_buffer_.size() >= end_of_transmission_.size())
        {
            bool end_match = true;
            for (size_t i = 0; i < end_of_transmission_.size(); ++i)
            {
                if (identifier_buffer_[identifier_buffer_.size() - end_of_transmission_.size() + i] != end_of_transmission_[i])
                {
                    end_match = false;
                    break;
                }
            }

            if (end_match)
            {
                // End transmission detected
                if (current_state_ == DataReceptionState::kWaitingForData || current_state_ == DataReceptionState::kReceivingData)
                {
                    // Extract received data
                    std::string received_text = "";

                    // Convert bits to bytes
                    std::vector<uint8_t> bytes = ConvertBitsToBytes(bit_buffer_);

                    // Convert to string
                    received_text.assign(bytes.begin(), bytes.end());

                    // Perform checksum validation if enabled
                    if (enable_checksum_validation_)
                    {
                        // Calculate checksum from received data
                        uint8_t calculated_checksum = CalculateChecksum(received_text);

                        // Extract checksum from the end of the data (assuming last byte is checksum)
                        if (!bytes.empty())
                        {
                            uint8_t received_checksum = bytes.back();

                            // Validate checksum
                            if (calculated_checksum != received_checksum)
                            {
                                ESP_LOGW(kLogTag, "Checksum validation failed");
                                current_state_ = DataReceptionState::kInactive;
                                return false;
                            }
                        }
                    }

                    // Set decoded text
                    decoded_text = received_text;

                    // Reset state
                    current_state_ = DataReceptionState::kInactive;
                    return true; // Successfully received complete data
                }
                else
                {
                    current_state_ = DataReceptionState::kInactive;
                }
            }
        }

        // Update state based on identifier detection
        if (current_state_ == DataReceptionState::kWaitingForData && 
            identifier_buffer_.size() >= start_of_transmission_.size())
        {
            // Check if we have enough bits to determine if we're actually receiving data
            // For now, we'll assume that once we've seen a start pattern, we're in receiving mode
            current_state_ = DataReceptionState::kReceivingData;
        }
    }

    return false; // No complete data received yet
}

void Backlight::SetBrightness(uint8_t brightness, bool permanent)
{
    // Early exit if brightness is unchanged
    if (brightness == brightness_)
    {
        return;
    }

    // Store the target brightness
    target_brightness_ = brightness;

    // Calculate step size for smooth transition
    int16_t diff = target_brightness_ - brightness_;
    const int steps = 20; // Number of steps for smooth transition
    step_ = diff / steps;

    // Start the transition timer if not already running
    if (transition_timer_ != nullptr)
    {
        esp_timer_start_periodic(transition_timer_, 10000); // 10ms interval
    }

    // Save to settings if requested
    if (permanent)
    {
        Settings settings("display");
        settings.SetInt("brightness", brightness);
    }
}

