std::string Board::GenerateUuid()
{
    uint8_t uuid[16];

    // Generate 16 bytes of random data
    esp_fill_random(uuid, sizeof(uuid));

    // Set the version bits (bits 12-15 of the time_hi_and_version field)
    uuid[6] = (uuid[6] & 0x0F) | 0x40;

    // Set the variant bits (bits 6-7 of the clock_seq_hi_res field)
    uuid[8] = (uuid[8] & 0x3F) | 0x80;

    // Format as UUID string: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
    char uuid_str[37]; // 36 characters + null terminator
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid[0], uuid[1], uuid[2], uuid[3],
             uuid[4], uuid[5],
             uuid[6], uuid[7],
             uuid[8], uuid[9],
             uuid[10], uuid[11], uuid[12], uuid[13], uuid[14], uuid[15]);

    return std::string(uuid_str);
}

std::string Board::GetSystemInfoJson()
{
    // Get system information
    uint32_t flash_size = SystemInfo::GetFlashSize();
    uint32_t psram_size = SystemInfo::GetPsramSize();
    uint32_t min_free_heap = esp_get_minimum_free_heap_size();

    // Get MAC address
    uint8_t mac[6];
    esp_efuse_mac_get_default(mac);
    char mac_str[18];
    snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);

    // Get chip information
    esp_chip_info_t chip_info;
    esp_chip_info(&chip_info);

    // Build JSON string
    std::string json = "{";
    json += "\"version\": 2,";
    json += "\"flash_size\": " + std::to_string(flash_size) + ",";
    json += "\"psram_size\": " + std::to_string(psram_size) + ",";
    json += "\"minimum_free_heap_size\": " + std::to_string(min_free_heap) + ",";
    json += "\"mac_address\": \"" + std::string(mac_str) + "\",";
    json += "\"uuid\": \"" + uuid_ + "\",";
    json += "\"chip_model_name\": \"" + std::string(BOARD_NAME) + "\",";
    json += "\"chip_info\": {";
    json += "\"model\": " + std::to_string(chip_info.model) + ",";
    json += "\"revision\": " + std::to_string(chip_info.revision) + ",";
    json += "\"cores\": " + std::to_string(chip_info.cores) + ",";
    json += "\"features\": " + std::to_string(chip_info.features);
    json += "}";
    json += "}";

    return json;
}

Esp32Camera::Esp32Camera(const esp_video_init_config_t &config)
{
    video_fd_ = -1;
    streaming_on_ = false;
    sensor_format_ = 0;
    sensor_width_ = 0;
    sensor_height_ = 0;
    frame_.data = nullptr;
    frame_.len = 0;
    frame_.format = 0;

    // Log available video devices if debug mode is enabled
#if CONFIG_XIAOZHI_ENABLE_CAMERA_DEBUG_MODE
    log_available_video_devices();
#endif

    // Determine video device path based on configuration
    const char *device_path = nullptr;

    // Try to find a suitable video device based on configuration
    // This is a simplified approach - in reality this would depend on the specific sensor type
    for (int i = 0; i < 5; i++) {  // Try first 5 video devices
        char path[16];
        snprintf(path, sizeof(path), "/dev/video%d", i);

        int fd = open(path, O_RDWR);
        if (fd >= 0) {
            device_path = path;
            video_fd_ = fd;
            break;
        }
    }

    if (video_fd_ < 0) {
        ESP_LOGE(TAG, "Failed to open any video device");
        return;
    }

    // Query device capabilities
    struct v4l2_capability cap = {};
    if (ioctl(video_fd_, VIDIOC_QUERYCAP, &cap) != 0) {
        ESP_LOGE(TAG, "VIDIOC_QUERYCAP failed");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    // Check if device supports video capture
    if (!(cap.capabilities & V4L2_CAP_VIDEO_CAPTURE)) {
        ESP_LOGE(TAG, "Video device does not support video capture");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    // Set pixel format and resolution from config
    struct v4l2_format fmt = {};
    fmt.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;

    // Set format based on config
    fmt.fmt.pix.width = config.width;
    fmt.fmt.pix.height = config.height;
    fmt.fmt.pix.pixelformat = config.pixel_format;
    fmt.fmt.pix.field = V4L2_FIELD_INTERLACED;

    if (ioctl(video_fd_, VIDIOC_S_FMT, &fmt) != 0) {
        ESP_LOGE(TAG, "VIDIOC_S_FMT failed");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    // Store actual format settings
    sensor_format_ = fmt.fmt.pix.pixelformat;
    sensor_width_ = fmt.fmt.pix.width;
    sensor_height_ = fmt.fmt.pix.height;

    // Print format information if debug is enabled
#if CONFIG_XIAOZHI_ENABLE_CAMERA_DEBUG_MODE
    CAM_PRINT_FOURCC(fmt.fmt.pix.pixelformat);
    ESP_LOGD(TAG, "Resolution: %dx%d", fmt.fmt.pix.width, fmt.fmt.pix.height);
#endif

    // Request memory mapping buffers
    struct v4l2_requestbuffers req = {};
    req.count = 4;
    req.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    req.memory = V4L2_MEMORY_MMAP;

    if (ioctl(video_fd_, VIDIOC_REQBUFS, &req) != 0) {
        ESP_LOGE(TAG, "VIDIOC_REQBUFS failed");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    if (req.count < 2) {
        ESP_LOGE(TAG, "Insufficient buffer memory");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    // Map buffers
    mmap_buffers_.resize(req.count);
    for (int i = 0; i < req.count; i++) {
        struct v4l2_buffer buf = {};
        buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
        buf.memory = V4L2_MEMORY_MMAP;
        buf.index = i;

        if (ioctl(video_fd_, VIDIOC_QUERYBUF, &buf) != 0) {
            ESP_LOGE(TAG, "VIDIOC_QUERYBUF failed");
            close(video_fd_);
            video_fd_ = -1;
            return;
        }

        mmap_buffers_[i].start = mmap(NULL, buf.length, PROT_READ | PROT_WRITE, MAP_SHARED, video_fd_, buf.m.offset);
        mmap_buffers_[i].length = buf.length;

        if (mmap_buffers_[i].start == MAP_FAILED) {
            ESP_LOGE(TAG, "mmap failed");
            close(video_fd_);
            video_fd_ = -1;
            return;
        }
    }

    // Queue all buffers
    for (int i = 0; i < req.count; i++) {
        struct v4l2_buffer buf = {};
        buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
        buf.memory = V4L2_MEMORY_MMAP;
        buf.index = i;

        if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0) {
            ESP_LOGE(TAG, "VIDIOC_QBUF failed");
            close(video_fd_);
            video_fd_ = -1;
            return;
        }
    }

    // Start streaming
    int type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    if (ioctl(video_fd_, VIDIOC_STREAMON, &type) != 0) {
        ESP_LOGE(TAG, "VIDIOC_STREAMON failed");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    streaming_on_ = true;

    // Initialize frame structure
    frame_.width = sensor_width_;
    frame_.height = sensor_height_;

    ESP_LOGI(TAG, "Camera initialized successfully: %dx%d, format: 0x%08lx", 
             sensor_width_, sensor_height_, sensor_format_);
}

bool Esp32Camera::Capture()
{
    if (video_fd_ < 0 || !streaming_on_)
    {
        ESP_LOGE(TAG, "Camera not initialized or streaming not active");
        return false;
    }

    struct v4l2_buffer buf = {};
    buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    buf.memory = V4L2_MEMORY_MMAP;

    // Dequeue buffer
    if (ioctl(video_fd_, VIDIOC_DQBUF, &buf) != 0)
    {
        ESP_LOGE(TAG, "VIDIOC_DQBUF failed, errno=%d(%s)", errno, strerror(errno));
        return false;
    }

    // Check if we have valid buffer
    if (buf.index >= mmap_buffers_.size())
    {
        ESP_LOGE(TAG, "Invalid buffer index: %u", buf.index);
        // Requeue the buffer before returning
        if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
        {
            ESP_LOGE(TAG, "Failed to requeue buffer, errno=%d(%s)", errno, strerror(errno));
        }
        return false;
    }

    // Get buffer info
    auto &buffer_info = mmap_buffers_[buf.index];

    // Copy frame data to our frame structure
    // Allocate memory for frame data
    if (frame_.data)
    {
        heap_caps_free(frame_.data);
        frame_.data = nullptr;
    }

    // Calculate frame size based on pixel format
    size_t frame_size = buf.bytesused;
    if (frame_size == 0)
    {
        frame_size = buffer_info.length;
    }

    // Allocate memory in PSRAM if available, otherwise regular RAM
    frame_.data = (uint8_t *)heap_caps_malloc(frame_size, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
    if (frame_.data == nullptr)
    {
        ESP_LOGW(TAG, "Failed to allocate PSRAM for frame, trying regular RAM");
        frame_.data = (uint8_t *)malloc(frame_size);
        if (frame_.data == nullptr)
        {
            ESP_LOGE(TAG, "Failed to allocate memory for frame");
            // Requeue the buffer before returning
            if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
            {
                ESP_LOGE(TAG, "Failed to requeue buffer, errno=%d(%s)", errno, strerror(errno));
            }
            return false;
        }
    }

    // Copy frame data
    memcpy(frame_.data, buffer_info.start, frame_size);
    frame_.len = frame_size;
    frame_.format = sensor_format_;

#ifdef CONFIG_XIAOZHI_ENABLE_ROTATE_CAMERA_IMAGE
    // Apply rotation if needed
    if (sensor_format_ != V4L2_PIX_FMT_JPEG)
    {
        uint8_t *rotated_data = nullptr;
        size_t rotated_len = 0;

        // Use PPA for ESP32-P4 or software rotation for other targets
#ifdef CONFIG_IDF_TARGET_ESP32P4
        // PPA-based rotation
        ppa_srm_config_t srm_cfg = {};
        srm_cfg.src_addr = frame_.data;
        srm_cfg.dst_addr = nullptr; // Will be allocated by PPA
        srm_cfg.src_w = sensor_width_;
        srm_cfg.src_h = sensor_height_;
        srm_cfg.dst_w = frame_.width;
        srm_cfg.dst_h = frame_.height;
        srm_cfg.rotation = IMAGE_ROTATION_ANGLE;
        srm_cfg.pixel_format = sensor_format_;

        if (ppa_srm_process(&srm_cfg, &rotated_data, &rotated_len) == ESP_OK)
        {
            // Free original data and update frame
            heap_caps_free(frame_.data);
            frame_.data = rotated_data;
            frame_.len = rotated_len;
        }
        else
        {
            ESP_LOGE(TAG, "PPA rotation failed");
        }
#else
        // Software rotation
        rotated_data = (uint8_t *)heap_caps_malloc(frame_.len, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
        if (rotated_data != nullptr)
        {
            if (esp_imgfx_rotate(frame_.data, frame_.len, sensor_width_, sensor_height_, 
                               IMAGE_ROTATION_ANGLE, rotated_data, &rotated_len, sensor_format_) == ESP_OK)
            {
                // Free original data and update frame
                heap_caps_free(frame_.data);
                frame_.data = rotated_data;
                frame_.len = rotated_len;
            }
            else
            {
                ESP_LOGE(TAG, "Software rotation failed");
                heap_caps_free(rotated_data);
            }
        }
#endif
    }
#endif

    // Requeue buffer for reuse
    if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
    {
        ESP_LOGE(TAG, "VIDIOC_QBUF failed, errno=%d(%s)", errno, strerror(errno));
        return false;
    }

    return true;
}

bool Esp32Camera::Capture()
{
    if (video_fd_ < 0 || !streaming_on_)
        return false;

    struct v4l2_buffer buf = {};
    buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    buf.memory = V4L2_MEMORY_MMAP;

    if (ioctl(video_fd_, VIDIOC_DQBUF, &buf) != 0)
    {
        ESP_LOGE(TAG, "VIDIOC_DQBUF failed, errno=%d(%s)", errno, strerror(errno));
        return false;
    }

    // Update frame info with captured buffer data
    frame_.data = static_cast<uint8_t*>(mmap_buffers_[buf.index].start);
    frame_.len = buf.bytesused;
    frame_.format = sensor_format_;

    // Requeue the buffer for next capture
    if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
    {
        ESP_LOGE(TAG, "VIDIOC_QBUF failed, errno=%d(%s)", errno, strerror(errno));
        return false;
    }

    return true;
}

