void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string &data)
{
    // Notify external callback if set
    if (network_event_callback_) {
        network_event_callback_(event, data);
    }

    switch (event) {
        case NetworkEvent::Connecting:
            // Stop any existing connection timer
            esp_timer_stop(connect_timer_);
            break;

        case NetworkEvent::Connected:
            // Stop connection timer when connected
            esp_timer_stop(connect_timer_);

            // Reset config mode flag
            in_config_mode_ = false;

            // Update device state
            Application::GetInstance().SetDeviceState(kDeviceStateIdle);

            // Release provisioning resources if needed
            // (This would typically be handled by the WifiManager itself)
            break;

        case NetworkEvent::Disconnected:
            // Stop connection timer
            esp_timer_stop(connect_timer_);

            // If we were in config mode, don't reconnect automatically
            if (!in_config_mode_) {
                // Restart connection attempt with timeout
                ESP_LOGI(TAG, "WiFi disconnected, attempting reconnection");
                esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000ULL);
                WifiManager::GetInstance().StartStation();
            }
            break;

        case NetworkEvent::Scanning:
            // No specific action needed for scanning
            break;

        case NetworkEvent::WifiConfigModeEnter:
            // We're already in config mode, just update state
            in_config_mode_ = true;
            break;

        case NetworkEvent::WifiConfigModeExit:
            // Exit config mode and attempt to reconnect
            in_config_mode_ = false;

            // Restart connection attempt with timeout
            ESP_LOGI(TAG, "Exiting WiFi config mode, attempting reconnection");
            esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000ULL);
            WifiManager::GetInstance().StartStation();
            break;
    }
}

void WifiBoard::StartWifiConfigMode()
{
    // Set device state to configuring mode
    auto &app = Application::GetInstance();
    app.SetDeviceState(kDeviceStateConfiguring);

    // Show notification to user
    GetDisplay()->ShowNotification(Lang::Strings::WIFI_CONFIG_MODE_NOTIFICATION);

#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Start BLUFI provisioning if enabled
    ESP_LOGI(TAG, "Starting BLUFI provisioning");
    Blufi::GetInstance().init();
    Blufi::GetInstance().start();
#else
    // Fallback to hotspot-based configuration
    ESP_LOGI(TAG, "Starting hotspot-based configuration");

    // Configure WiFi in AP mode for hotspot
    WifiManagerConfig config;
    config.ssid_prefix = "Xiaozhi-Config";
    config.language = Lang::CODE;
    WifiManager::GetInstance().Initialize(config);

    // Start access point mode
    WifiManager::GetInstance().StartAccessPoint();
#endif

    // Update network state icon
    GetDisplay()->UpdateNetworkStateIcon();
}

void WifiBoard::EnterWifiConfigMode()
{
    // Stop any ongoing WiFi connection attempts
    WifiManager::GetInstance().StopStation();

    // Stop timeout timer if running
    esp_timer_stop(connect_timer_);

    // Reset any active audio/communication processes
    auto &app = Application::GetInstance();
    auto &board = Board::GetInstance();

    // Stop any ongoing audio playback or recording
    if (auto codec = board.GetAudioCodec()) {
        codec->stop();
    }

    // Stop any ongoing network operations
    WifiManager::GetInstance().StopStation();

    // Enter Wi-Fi configuration mode
    StartWifiConfigMode();
}

std::string WifiBoard::GetDeviceStatusJson()
{
    auto &wifi = WifiManager::GetInstance();
    auto &audio = Board::GetInstance().GetAudioCodec();
    auto &display = Board::GetInstance().GetDisplay();
    auto &power = PowerManager::GetInstance();

    std::string json = "{";

    // Audio speaker volume
    if (audio) {
        json += "\"volume\":" + std::to_string(audio->volume()) + ",";
    } else {
        json += "\"volume\":0,";
    }

    // Screen brightness and theme
    if (display) {
        json += "\"brightness\":" + std::to_string(display->brightness()) + ",";
        json += "\"theme\":\"" + display->theme() + "\",";
    } else {
        json += "\"brightness\":0,\"theme\":\"default\",";
    }

    // Battery level and charging state
    json += "\"battery\":" + std::to_string(power.GetBatteryLevel()) + ",";
    json += "\"charging\":" + std::to_string(power.IsCharging() ? 1 : 0) + ",";

    // WiFi network details
    if (!wifi.IsConfigMode()) {
        json += "\"ssid\":\"" + wifi.GetSsid() + "\",";
        json += "\"rssi\":" + std::to_string(wifi.GetRssi()) + ",";
    } else {
        json += "\"ssid\":\"\",\"rssi\":0,";
    }

    // Chip temperature
    json += "\"temperature\":" + std::to_string(SystemInfo::GetChipTemperature()) + ",";

    // Remove trailing comma and close JSON
    if (json.back() == ',') {
        json.pop_back();
    }
    json += "}";

    return json;
}

void LcdDisplay::InitializeLcdThemes()
{
    // Create light theme
    auto light_theme = std::make_shared<LvglTheme>();

    // Set light theme properties
    light_theme->set_name("light");
    light_theme->set_text_font(&BUILTIN_TEXT_FONT);
    light_theme->set_icon_font(&BUILTIN_ICON_FONT);
    light_theme->set_large_icon_font(&font_awesome_30_4);
    light_theme->set_background_color(lv_color_white());
    light_theme->set_text_color(lv_color_black());
    light_theme->set_border_color(lv_color_grey());
    light_theme->set_chat_background_color(lv_color_white());
    light_theme->set_user_bubble_color(lv_color_make(0x4D, 0xB3, 0xFF));
    light_theme->set_assistant_bubble_color(lv_color_white());
    light_theme->set_system_bubble_color(lv_color_light_grey());
    light_theme->set_system_text_color(lv_color_dark_grey());
    light_theme->set_low_battery_color(lv_color_red());
    light_theme->set_spacing(4);

    // Create dark theme
    auto dark_theme = std::make_shared<LvglTheme>();

    // Set dark theme properties
    dark_theme->set_name("dark");
    dark_theme->set_text_font(&BUILTIN_TEXT_FONT);
    dark_theme->set_icon_font(&BUILTIN_ICON_FONT);
    dark_theme->set_large_icon_font(&font_awesome_30_4);
    dark_theme->set_background_color(lv_color_black());
    dark_theme->set_text_color(lv_color_white());
    dark_theme->set_border_color(lv_color_grey());
    dark_theme->set_chat_background_color(lv_color_black());
    dark_theme->set_user_bubble_color(lv_color_make(0x4D, 0xB3, 0xFF));
    dark_theme->set_assistant_bubble_color(lv_color_dark_grey());
    dark_theme->set_system_bubble_color(lv_color_grey());
    dark_theme->set_system_text_color(lv_color_light_grey());
    dark_theme->set_low_battery_color(lv_color_red());
    dark_theme->set_spacing(4);

    // Register themes with the theme manager
    LvglThemeManager::GetInstance().RegisterTheme(light_theme);
    LvglThemeManager::GetInstance().RegisterTheme(dark_theme);
}

LcdDisplay::LcdDisplay(esp_lcd_panel_io_handle_t panel_io, esp_lcd_panel_handle_t panel, int width, int height)
    : panel_io_(panel_io), panel_(panel), width_(width), height_(height)
{
    // Initialize LCD themes
    InitializeLcdThemes();

    // Load theme from settings
    Settings settings("display", false);
    std::string theme_name = settings.GetString("theme", "light");
    current_theme_ = LvglThemeManager::GetInstance().GetTheme(theme_name);

    // Create a timer to hide the preview image
    esp_timer_create_args_t preview_timer_args = {
        .callback = [](void *arg)
        {
            LcdDisplay *display = static_cast<LcdDisplay *>(arg);
            display->SetPreviewImage(nullptr);
        },
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK,
        .name = "preview_timer",
        .skip_unhandled_events = false,
    };
    esp_timer_create(&preview_timer_args, &preview_timer_);
}

SpiLcdDisplay::SpiLcdDisplay(esp_lcd_panel_io_handle_t panel_io, esp_lcd_panel_handle_t panel,
                             int width, int height, int offset_x, int offset_y,
                             bool mirror_x, bool mirror_y, bool swap_xy)
    : LcdDisplay(panel_io, panel, width, height)
{
    // draw white
    std::vector<uint16_t> buffer(width_, 0xFFFF);
    for (int y = 0; y < height_; y++)
    {
        esp_lcd_panel_draw_bitmap(panel_, 0, y, width_, y + 1, buffer.data());
    }

    ESP_LOGI(TAG, "Initialize LVGL library");
    lv_init();

    ESP_LOGI(TAG, "Initialize LVGL port");
    lvgl_port_cfg_t port_cfg = ESP_LVGL_PORT_INIT_CONFIG();
    port_cfg.task_priority = 1;
    port_cfg.timer_period_ms = 50;
    lvgl_port_init(&port_cfg);

    ESP_LOGI(TAG, "Adding LCD display");
    const lvgl_port_display_cfg_t display_cfg = {
        .io_handle = panel_io_,
        .panel_handle = panel_,
        .buffer_size = static_cast<uint32_t>(width_ * 20),
        .double_buffer = true,
        .hres = static_cast<uint32_t>(width_),
        .vres = static_cast<uint32_t>(height_),
        .rotation = {
            .swap_xy = swap_xy,
            .mirror_x = mirror_x,
            .mirror_y = mirror_y,
        },
        .flags = {
            .buff_dma = 1,
            .swap_bytes = 0,
            .full_refresh = 1,
            .direct_mode = 1,
        },
    };

    display_ = lvgl_port_add_disp(&display_cfg);
    if (display_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to add SPI display");
        return;
    }

    if (offset_x != 0 || offset_y != 0)
    {
        lv_display_set_offset(display_, offset_x, offset_y);
    }

    SetupUI();
}

RgbLcdDisplay::RgbLcdDisplay(esp_lcd_panel_io_handle_t panel_io, esp_lcd_panel_handle_t panel,
                             int width, int height, int offset_x, int offset_y, bool mirror_x, bool mirror_y, bool swap_xy)
    : LcdDisplay(panel_io, panel, width, height)
{
    // draw white
    std::vector<uint16_t> buffer(width_, 0xFFFF);
    for (int y = 0; y < height_; y++)
    {
        esp_lcd_panel_draw_bitmap(panel_, 0, y, width_, y + 1, buffer.data());
    }

    // Set the display to on
    ESP_LOGI(TAG, "Turning display on");
    {
        esp_err_t __err = esp_lcd_panel_disp_on_off(panel_, true);
        if (__err == ESP_ERR_NOT_SUPPORTED)
        {
            ESP_LOGW(TAG, "Panel does not support disp_on_off; assuming ON");
        }
        else
        {
            ESP_ERROR_CHECK(__err);
        }
    }

    ESP_LOGI(TAG, "Initialize LVGL library");
    lv_init();

#if CONFIG_SPIRAM
    // lv image cache, currently only PNG is supported
    size_t psram_size_mb = esp_psram_get_size() / 1024 / 1024;
    if (psram_size_mb >= 8)
    {
        lv_image_cache_resize(2 * 1024 * 1024, true);
        ESP_LOGI(TAG, "Use 2MB of PSRAM for image cache");
    }
    else if (psram_size_mb >= 2)
    {
        lv_image_cache_resize(512 * 1024, true);
        ESP_LOGI(TAG, "Use 512KB of PSRAM for image cache");
    }
#endif

    ESP_LOGI(TAG, "Initialize LVGL port");
    lvgl_port_cfg_t port_cfg = ESP_LVGL_PORT_INIT_CONFIG();
    port_cfg.task_priority = 1;
#if CONFIG_SOC_CPU_CORES_NUM > 1
    port_cfg.task_affinity = 1;
#endif
    lvgl_port_init(&port_cfg);

    ESP_LOGI(TAG, "Adding LCD display");
    const lvgl_port_display_cfg_t display_cfg = {
        .io_handle = panel_io_,
        .panel_handle = panel_,
        .control_handle = nullptr,
        .buffer_size = static_cast<uint32_t>(width_ * 20),
        .double_buffer = false,
        .trans_size = 0,
        .hres = static_cast<uint32_t>(width_),
        .vres = static_cast<uint32_t>(height_),
        .monochrome = false,
        .rotation = {
            .swap_xy = swap_xy,
            .mirror_x = mirror_x,
            .mirror_y = mirror_y,
        },
        .color_format = LV_COLOR_FORMAT_RGB565,
        .flags = {
            .buff_dma = 1,
            .buff_spiram = 0,
            .sw_rotate = 0,
            .swap_bytes = 1,
            .full_refresh = 0,
            .direct_mode = 0,
        },
    };

    display_ = lvgl_port_add_disp(&display_cfg);
    if (display_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to add display");
        return;
    }

    if (offset_x != 0 || offset_y != 0)
    {
        lv_display_set_offset(display_, offset_x, offset_y);
    }

    SetupUI();
}

