LcdDisplay::~LcdDisplay()
{
    // Stop and delete GIF controller if exists
    if (gif_controller_) {
        gif_controller_->Stop();
        gif_controller_.reset();
    }

    // Delete the preview timer
    if (preview_timer_) {
        esp_timer_delete(preview_timer_);
    }

    // Clean up UI elements
    if (top_bar_) {
        lv_obj_clean(top_bar_);
        lv_obj_del(top_bar_);
        top_bar_ = nullptr;
    }

    if (status_bar_) {
        lv_obj_clean(status_bar_);
        lv_obj_del(status_bar_);
        status_bar_ = nullptr;
