    }

    if (chat_message_label_) {
        lv_obj_clean(chat_message_label_);
        lv_obj_del(chat_message_label_);
        chat_message_label_ = nullptr;
    }

    if (emoji_label_) {
        lv_obj_clean(emoji_label_);
        lv_obj_del(emoji_label_);
        emoji_label_ = nullptr;
    }

    if (emoji_image_) {
        lv_obj_clean(emoji_image_);
        lv_obj_del(emoji_image_);
        emoji_image_ = nullptr;
    }

    if (low_battery_popup_) {
        lv_obj_clean(low_battery_popup_);
        lv_obj_del(low_battery_popup_);
        low_battery_popup_ = nullptr;
