#if CONFIG_IDF_TARGET_ESP32P4
#define MAX_MESSAGES 40
#else
#define MAX_MESSAGES 20
#endif
void LcdDisplay::SetChatMessage(const char *role, const char *content)
{
    DisplayLockGuard lock(this);

    if (content_ == nullptr || content == nullptr) {
        return;
    }

    // Don't display empty messages
    if (strlen(content) == 0) {
        return;
    }

    // Hide the AI logo when showing non-system messages
    if (emoji_label_ != nullptr && strcmp(role, "system") != 0) {
        lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
    }

    // Create a message bubble based on role
    lv_obj_t *msg_bubble = lv_obj_create(content_);
    lv_obj_set_style_radius(msg_bubble, 8, 0);
    lv_obj_set_scrollbar_mode(msg_bubble, LV_SCROLLBAR_MODE_OFF);
    lv_obj_set_style_border_width(msg_bubble, 0, 0);
    lv_obj_set_style_pad_all(msg_bubble, 8, 0);

    auto lvgl_theme = static_cast<LvglTheme *>(current_theme_);

    // Set bubble background color based on role
    if (strcmp(role, "user") == 0) {
        lv_obj_set_style_bg_color(msg_bubble, lvgl_theme->user_bubble_color(), 0);
        lv_obj_set_style_bg_opa(msg_bubble, LV_OPA_70, 0);
        lv_obj_set_user_data(msg_bubble, (void *)"user");
    } else if (strcmp(role, "assistant") == 0) {
        lv_obj_set_style_bg_color(msg_bubble, lvgl_theme->assistant_bubble_color(), 0);
        lv_obj_set_style_bg_opa(msg_bubble, LV_OPA_70, 0);
        lv_obj_set_user_data(msg_bubble, (void *)"assistant");
    } else if (strcmp(role, "system") == 0) {
        lv_obj_set_style_bg_color(msg_bubble, lvgl_theme->system_bubble_color(), 0);
        lv_obj_set_style_bg_opa(msg_bubble, LV_OPA_70, 0);
        lv_obj_set_user_data(msg_bubble, (void *)"system");
    } else {
        // Default to assistant style for unknown roles
        lv_obj_set_style_bg_color(msg_bubble, lvgl_theme->assistant_bubble_color(), 0);
        lv_obj_set_style_bg_opa(msg_bubble, LV_OPA_70, 0);
        lv_obj_set_user_data(msg_bubble, (void *)"assistant");
    }

    // Set border color
    lv_obj_set_style_border_color(msg_bubble, lvgl_theme->border_color(), 0);

    // Create label inside bubble for message text
    lv_obj_t *msg_label = lv_label_create(msg_bubble);
    lv_label_set_text(msg_label, content);
    lv_obj_set_width(msg_label, LV_HOR_RES * 70 / 100); // Limit width to 70% of screen

    // Set text color based on role
    if (strcmp(role, "system") == 0) {
        lv_obj_set_style_text_color(msg_label, lvgl_theme->system_text_color(), 0);
    } else {
        lv_obj_set_style_text_color(msg_label, lvgl_theme->text_color(), 0);
    }

    // Set text alignment
    lv_label_set_long_mode(msg_label, LV_LABEL_LONG_WRAP);
    lv_obj_set_style_text_align(msg_label, LV_TEXT_ALIGN_LEFT, 0);

    // Set bubble size and positioning
    lv_obj_set_style_flex_grow(msg_bubble, 0, 0);

    // Position based on role
    if (strcmp(role, "user") == 0) {
        lv_obj_align(msg_bubble, LV_ALIGN_RIGHT_MID, 0, 0);
    } else {
        lv_obj_align(msg_bubble, LV_ALIGN_LEFT_MID, 0, 0);
    }

    // Auto-scroll to the new message
    lv_obj_scroll_to_view_recursive(msg_bubble, LV_ANIM_ON);

    // Manage message history - remove oldest messages if needed
    uint32_t child_count = lv_obj_get_child_cnt(content_);
    if (child_count > MAX_MESSAGES) {
        // Remove the oldest message (first child)
        lv_obj_t *oldest_msg = lv_obj_get_child(content_, 0);
        if (oldest_msg != nullptr) {
            lv_obj_del(oldest_msg);
        }
    }
}

#if CONFIG_USE_WECHAT_MESSAGE_STYLE
void LcdDisplay::SetPreviewImage(std::unique_ptr<LvglImage> image)
{
    DisplayLockGuard lock(this);
    if (content_ == nullptr)
    {
        return;
    }

    if (image == nullptr)
    {
        // Clean up existing preview image
        // Note: The original code has logic for this but it's incomplete in the provided snippet
        // We need to handle the case where we're clearing the preview
        return;
    }

    auto lvgl_theme = static_cast<LvglTheme *>(current_theme_);
    // Create a message bubble for image preview
    lv_obj_t *img_bubble = lv_obj_create(content_);
    lv_obj_set_style_radius(img_bubble, 8, 0);
    lv_obj_set_scrollbar_mode(img_bubble, LV_SCROLLBAR_MODE_OFF);
    lv_obj_set_style_border_width(img_bubble, 0, 0);
    lv_obj_set_style_pad_all(img_bubble, lvgl_theme->spacing(4), 0);

    // Set image bubble background color (similar to system message)
    lv_obj_set_style_bg_color(img_bubble, lvgl_theme->assistant_bubble_color(), 0);
    lv_obj_set_style_bg_opa(img_bubble, LV_OPA_70, 0);

    // Set custom attribute to mark bubble type
    lv_obj_set_user_data(img_bubble, (void *)"image");

    // Create the image object inside the bubble
    lv_obj_t *preview_image = lv_image_create(img_bubble);

    // Calculate appropriate size for the image
    lv_coord_t max_width = LV_HOR_RES * 70 / 100;  // 70% of screen width
    lv_coord_t max_height = LV_VER_RES * 50 / 100; // 50% of screen height

    // Calculate zoom factor to fit within maximum dimensions
    auto img_dsc = image->image_dsc();
    lv_coord_t img_width = img_dsc->header.w;
    lv_coord_t img_height = img_dsc->header.h;
    if (img_width == 0 || img_height == 0)
    {
        img_width = max_width;
        img_height = max_height;
        ESP_LOGW(TAG, "Invalid image dimensions: %ld x %ld, using default dimensions: %ld x %ld", img_width, img_height, max_width, max_height);
    }

    lv_coord_t zoom_w = (max_width * 256) / img_width;
    lv_coord_t zoom_h = (max_height * 256) / img_height;
    lv_coord_t zoom = (zoom_w < zoom_h) ? zoom_w : zoom_h;

    // Ensure zoom doesn't exceed 256 (100%)
    if (zoom > 256)
        zoom = 256;

    // Set image properties
    lv_image_set_src(preview_image, img_dsc);
    lv_image_set_scale(preview_image, zoom);

    // Add event handler to clean up LvglImage when image is deleted
    // We need to transfer ownership of the unique_ptr to the event callback
    LvglImage *raw_image = image.release(); // Release ownership of smart pointer
    lv_obj_add_event_cb(preview_image, [](lv_event_t *e)
                        {
        LvglImage* img = (LvglImage*)lv_event_get_user_data(e);
        if (img != nullptr) {
            delete img; // Properly release memory by deleting LvglImage object
        } }, LV_EVENT_DELETE, (void *)raw_image);

    // Calculate actual scaled image dimensions
    lv_coord_t scaled_width = (img_width * zoom) / 256;
    lv_coord_t scaled_height = (img_height * zoom) / 256;

    // Set bubble size to be 16 pixels larger than the image (8 pixels on each side)
    lv_obj_set_width(img_bubble, scaled_width + 16);
    lv_obj_set_height(img_bubble, scaled_height + 16);

    // Don't grow in flex layout
    lv_obj_set_style_flex_grow(img_bubble, 0, 0);

    // Center the image within the bubble
    lv_obj_center(preview_image);

    // Left align the image bubble like assistant messages
    lv_obj_align(img_bubble, LV_ALIGN_LEFT_MID, 0, 0);

    // Auto-scroll to the image bubble
    lv_obj_scroll_to_view_recursive(img_bubble, LV_ANIM_ON);
}
