    if (content == nullptr || strlen(content) == 0)
    {
        if (chat_message_label_ != nullptr)
        {
            lv_label_set_text(chat_message_label_, "");
        }
        return;
    }

#if CONFIG_USE_WECHAT_MESSAGE_STYLE
    // In WeChat message style, create message bubbles
    if (content_ == nullptr)
        return;

    // Remove the AI logo when showing non-system messages
    if (strcmp(role, "system") != 0 && emoji_image_ != nullptr)
    {
        lv_obj_add_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
    }

    // Create message bubble
    lv_obj_t *msg_bubble = lv_obj_create(content_);
    lv_obj_set_style_radius(msg_bubble, 10, 0);
    lv_obj_set_style_bg_color(msg_bubble, lv_color_black(), 0); // Default color
    lv_obj_set_style_border_width(msg_bubble, 1, 0);
    lv_obj_set_style_border_color(msg_bubble, lv_color_black(), 0);
    lv_obj_set_style_pad_all(msg_bubble, 8, 0);
    lv_obj_set_style_pad_row(msg_bubble, 4, 0);
    lv_obj_set_style_bg_opa(msg_bubble, LV_OPA_70, 0);

    // Create message text
    lv_obj_t *msg_text = lv_label_create(msg_bubble);
    lv_label_set_text(msg_text, content);
    lv_obj_set_width(msg_text, LV_PCT(100));
    lv_label_set_long_mode(msg_text, LV_LABEL_LONG_WRAP);
    lv_obj_set_style_text_align(msg_text, LV_TEXT_ALIGN_LEFT, 0);
    lv_obj_set_style_text_color(msg_text, lv_color_white(), 0);

    // Set appropriate styling based on role
    if (strcmp(role, "user") == 0)
    {
        lv_obj_set_style_bg_color(msg_bubble, lvgl_theme_->user_bubble_color(), 0);
        lv_obj_set_style_border_color(msg_bubble, lvgl_theme_->border_color(), 0);
        lv_obj_set_style_text_color(msg_text, lvgl_theme_->text_color(), 0);

        // Create a full-width container for user messages to ensure right alignment
        lv_obj_t *container = lv_obj_create(content_);
        lv_obj_set_width(container, LV_HOR_RES);
        lv_obj_set_height(container, LV_SIZE_CONTENT);
        lv_obj_set_style_bg_opa(container, LV_OPA_TRANSP, 0);
        lv_obj_set_style_border_width(container, 0, 0);
        lv_obj_set_style_pad_all(container, 0, 0);
        lv_obj_set_parent(msg_bubble, container);
        lv_obj_align(msg_bubble, LV_ALIGN_RIGHT_MID, -25, 0);
        lv_obj_scroll_to_view_recursive(container, LV_ANIM_ON);

        // Set custom attribute to mark bubble type
        lv_obj_set_user_data(msg_bubble, (void *)"user");
    }
    else if (strcmp(role, "system") == 0)
    {
        lv_obj_set_style_bg_color(msg_bubble, lvgl_theme_->system_bubble_color(), 0);
        lv_obj_set_style_border_color(msg_bubble, lvgl_theme_->border_color(), 0);
        lv_obj_set_style_text_color(msg_text, lvgl_theme_->system_text_color(), 0);

        // Create full-width container for system messages to ensure center alignment
        lv_obj_t *container = lv_obj_create(content_);
        lv_obj_set_width(container, LV_HOR_RES);
        lv_obj_set_height(container, LV_SIZE_CONTENT);
        lv_obj_set_style_bg_opa(container, LV_OPA_TRANSP, 0);
        lv_obj_set_style_border_width(container, 0, 0);
        lv_obj_set_style_pad_all(container, 0, 0);
        lv_obj_set_parent(msg_bubble, container);
        lv_obj_align(msg_bubble, LV_ALIGN_CENTER, 0, 0);
        lv_obj_scroll_to_view_recursive(container, LV_ANIM_ON);

        // Set custom attribute to mark bubble type
        lv_obj_set_user_data(msg_bubble, (void *)"system");
    }
    else
    {
        // For assistant messages (default)
        lv_obj_set_style_bg_color(msg_bubble, lvgl_theme_->assistant_bubble_color(), 0);
        lv_obj_set_style_border_color(msg_bubble, lvgl_theme_->border_color(), 0);
        lv_obj_set_style_text_color(msg_text, lvgl_theme_->text_color(), 0);

        // Left align assistant messages
        lv_obj_align(msg_bubble, LV_ALIGN_LEFT_MID, 0, 0);
        lv_obj_scroll_to_view_recursive(msg_bubble, LV_ANIM_ON);

        // Set custom attribute to mark bubble type
        lv_obj_set_user_data(msg_bubble, (void *)"assistant");
    }

    // Store reference to the latest message label
    chat_message_label_ = msg_text;
#else
    // Simple UI mode - just update the main chat message
    if (chat_message_label_ != nullptr)
    {
        lv_label_set_text(chat_message_label_, content);
    }
#endif
}

void LcdDisplay::SetTheme(Theme *theme)
{
    DisplayLockGuard lock(this);

    if (theme == nullptr) {
        return;
    }

    // Update the current theme
    current_theme_ = theme;

    // Cast to LvglTheme to access theme-specific properties
    auto lvgl_theme = static_cast<LvglTheme *>(current_theme_);
    auto text_font = lvgl_theme->text_font()->font();
    auto icon_font = lvgl_theme->icon_font()->font();
    auto large_icon_font = lvgl_theme->large_icon_font()->font();

    // Apply theme to main screen
    auto screen = lv_screen_active();
    lv_obj_set_style_text_font(screen, text_font, 0);
    lv_obj_set_style_text_color(screen, lvgl_theme->text_color(), 0);
    lv_obj_set_style_bg_color(screen, lvgl_theme->background_color(), 0);

