        lv_obj_set_style_bg_opa(status_bar_, LV_OPA_TRANSP, 0);
    }

    // Update notification label
    if (notification_label_ != nullptr) {
        lv_obj_set_style_text_color(notification_label_, lvgl_theme->text_color(), 0);
    }

    // Update status label
    if (status_label_ != nullptr) {
        lv_obj_set_style_text_color(status_label_, lvgl_theme->text_color(), 0);
    }

    // Update content area background
    if (content_ != nullptr) {
        lv_obj_set_style_bg_color(content_, lvgl_theme->chat_background_color(), 0);
    }

    // Update low battery popup
    if (low_battery_popup_ != nullptr) {
        lv_obj_set_style_bg_color(low_battery_popup_, lvgl_theme->low_battery_color(), 0);
        lv_obj_set_style_radius(low_battery_popup_, lvgl_theme->spacing(4), 0);
    }

    // Update low battery label
    if (low_battery_label_ != nullptr) {
        lv_obj_set_style_text_color(low_battery_label_, lv_color_white(), 0);
    }

    // Update emoji label
    if (emoji_label_ != nullptr) {
        lv_obj_set_style_text_font(emoji_label_, large_icon_font, 0);
        lv_obj_set_style_text_color(emoji_label_, lvgl_theme->text_color(), 0);
    }

    // Update emoji image
    if (emoji_image_ != nullptr) {
        // The emoji image will be updated when SetEmotion is called
    }

    // Update preview image if exists
    if (preview_image_ != nullptr) {
        // Preview image styling is handled in SetPreviewImage
    }

    // Update chat message labels (if they exist)
    if (chat_message_label_ != nullptr) {
        lv_obj_set_style_text_color(chat_message_label_, lvgl_theme->text_color(), 0);
    }

    // Update bottom bar styles
    if (bottom_bar_ != nullptr) {
        lv_obj_set_style_bg_color(bottom_bar_, lvgl_theme->background_color(), 0);
        lv_obj_set_style_text_color(bottom_bar_, lvgl_theme->text_color(), 0);
    }

    // Update chat message label in bottom bar
    if (chat_message_label_ != nullptr) {
        lv_obj_set_style_text_color(chat_message_label_, lvgl_theme->text_color(), 0);
    }

    // Update all existing message bubbles with new theme colors
    if (content_ != nullptr) {
        uint32_t child_count = lv_obj_get_child_cnt(content_);
        for (uint32_t i = 0; i < child_count; i++) {
            lv_obj_t *child = lv_obj_get_child(content_, i);
            if (child != nullptr && lv_obj_get_child_cnt(child) > 0) {
                lv_obj_t *bubble = lv_obj_get_child(child, 0);
                if (bubble != nullptr) {
                    void *bubble_type_ptr = lv_obj_get_user_data(bubble);
                    if (bubble_type_ptr != nullptr) {
                        const char *bubble_type = (const char *)bubble_type_ptr;
                        if (strcmp(bubble_type, "user") == 0) {
                            lv_obj_set_style_bg_color(bubble, lvgl_theme->user_bubble_color(), 0);
                            lv_obj_set_style_bg_opa(bubble, LV_OPA_70, 0);
                        } else if (strcmp(bubble_type, "assistant") == 0) {
                            lv_obj_set_style_bg_color(bubble, lvgl_theme->assistant_bubble_color(), 0);
                            lv_obj_set_style_bg_opa(bubble, LV_OPA_70, 0);
                        } else if (strcmp(bubble_type, "system") == 0) {
                            lv_obj_set_style_bg_color(bubble, lvgl_theme->system_bubble_color(), 0);
                            lv_obj_set_style_bg_opa(bubble, LV_OPA_70, 0);
                        } else if (strcmp(bubble_type, "image") == 0) {
                            lv_obj_set_style_bg_color(bubble, lvgl_theme->assistant_bubble_color(), 0);
                            lv_obj_set_style_bg_opa(bubble, LV_OPA_70, 0);
                        }
                    }
                }
            }
        }
    }
}

SingleLed::SingleLed(gpio_num_t gpio)
{
    // Initialize LED strip configuration
    led_strip_config_t led_strip_cfg = LED_STRIP_DEFAULT_CONFIG(gpio, LED_STRIP_RMT_TIMER, 1);

    // Create LED strip
    esp_err_t ret = led_strip_new_rmt_device(&led_strip_cfg, &led_strip_);
    if (ret != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to create LED strip");
        led_strip_ = nullptr;
        return;
    }

    // Initialize default color values
    r_ = 0;
    g_ = 0;
    b_ = 0;

    // Initialize blink counter and interval
    blink_counter_ = 0;
    blink_interval_ms_ = 0;

    // Create blinking timer
    const esp_timer_create_args_t timer_args = {
        .callback = [](void *arg) {
            SingleLed* led = static_cast<SingleLed*>(arg);
            led->OnBlinkTimer();
        },
        .arg = this,
        .name = "led_blink",
        .dispatch_method = ESP_TIMER_TASK,
        .skip_unhandled_events = true
    };

    ret = esp_timer_create(&timer_args, &blink_timer_);
    if (ret != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to create blink timer");
        esp_timer_delete(blink_timer_);
        blink_timer_ = nullptr;
        return;
    }

    // Clear the LED initially
    led_strip_clear(led_strip_);
}

void SingleLed::OnStateChanged()
{
    auto &app = Application::GetInstance();
    auto device_state = app.GetDeviceState();
    switch (device_state)
    {
    case kDeviceStateStarting:
        SetColor(0, 0, DEFAULT_BRIGHTNESS);
        StartContinuousBlink(100);
        break;
    case kDeviceStateWifiConfiguring:
        SetColor(0, 0, DEFAULT_BRIGHTNESS);
        StartContinuousBlink(200);
        break;
    case kDeviceStateIdle:
        SetColor(0, DEFAULT_BRIGHTNESS, 0);
        TurnOn();
        break;
    case kDeviceStateConnecting:
        SetColor(DEFAULT_BRIGHTNESS, DEFAULT_BRIGHTNESS, 0);
        StartContinuousBlink(500);
        break;
    case kDeviceStateListening:
        SetColor(DEFAULT_BRIGHTNESS, 0, DEFAULT_BRIGHTNESS);
        StartContinuousBlink(300);
        break;
    case kDeviceStateSpeaking:
        SetColor(DEFAULT_BRIGHTNESS, 0, 0);
        StartContinuousBlink(100);
        break;
    case kDeviceStateUpgrading:
        SetColor(HIGH_BRIGHTNESS, HIGH_BRIGHTNESS, HIGH_BRIGHTNESS);
        StartContinuousBlink(200);
        break;
    case kDeviceStateActivating:
        SetColor(LOW_BRIGHTNESS, LOW_BRIGHTNESS, LOW_BRIGHTNESS);
        StartContinuousBlink(1000);
        break;
    default:
        TurnOff();
        break;
    }
}

cpp
MqttProtocol::MqttProtocol()
{
    // Initialize event group for synchronization
    event_group_handle_ = xEventGroupCreate();
    if (event_group_handle_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create event group");
        return;
    }

    // Initialize reconnect timer
    const esp_timer_create_args_t timer_args = {
        .callback = [](void *arg) {
            MqttProtocol* self = static_cast<MqttProtocol*>(arg);
            // Schedule reconnect via application's task scheduler
            Application::GetInstance().Schedule([self]() {
                self->StartMqttClient(false);
            });
        },
        .name = "mqtt_reconnect",
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK
    };

    esp_timer_err_t err = esp_timer_create(&timer_args, &reconnect_timer_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create reconnect timer: %s", esp_err_to_name(err));
        return;
    }

    // Initialize other members
    alive_ = new bool(true);
    error_occurred_ = false;
    last_incoming_time_ = std::chrono::steady_clock::now();
    local_sequence_ = 0;
    remote_sequence_ = 0;
    server_sample_rate_ = 16000;
    server_frame_duration_ = OPUS_FRAME_DURATION_MS;
}

bool MqttProtocol::StartMqttClient(bool report_error)
{
    // Check if MQTT client is already initialized
    if (mqtt_ != nullptr)
    {
        if (mqtt_->IsConnected())
        {
            return true;
        }
        else
        {
            mqtt_.reset();
        }
    }

    // Create new MQTT client instance
    auto network = Board::GetInstance().GetNetwork();
    mqtt_ = network->CreateMqtt();

    if (mqtt_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to create MQTT client");
        if (report_error)
        {
            SetError(Lang::Strings::CONNECTION_ERROR);
        }
        return false;
    }

    // Configure MQTT settings
    mqtt_->SetBrokerEndpoint(settings_.mqtt_broker_endpoint);
    mqtt_->SetClientId(settings_.device_id);
    mqtt_->SetUsername(settings_.mqtt_username);
    mqtt_->SetPassword(settings_.mqtt_password);

    // Set up connection handlers
    mqtt_->OnConnected([this]()
                       {
        ESP_LOGI(TAG, "MQTT connected");
        // Subscribe to the topic after connecting
        if (!subscribe_topic_.empty())
        {
            if (!mqtt_->Subscribe(subscribe_topic_))
            {
                ESP_LOGE(TAG, "Failed to subscribe to topic: %s", subscribe_topic_.c_str());
                SetError(Lang::Strings::SUBSCRIBE_ERROR);
            }
        }
        // Clear error state on successful connection
        error_occurred_ = false;
        // Set alive flag to true for reconnect logic
        *alive_ = true; });

    mqtt_->OnDisconnected([this]()
                          {
        ESP_LOGI(TAG, "MQTT disconnected");
        // Cancel any pending scheduled tasks
        *alive_ = false;
        // Schedule reconnect attempt
        if (reconnect_timer_ != nullptr)
        {
            esp_timer_start_once(reconnect_timer_, settings_.mqtt_reconnect_interval_ms * 1000);
        }
        // Set error state on disconnection
        error_occurred_ = true; });

    mqtt_->OnMessage([this](const std::string &topic, const std::string &payload)
                     {
        ESP_LOGD(TAG, "MQTT message received on topic: %s", topic.c_str());

        // Parse JSON payload
        cJSON *root = cJSON_Parse(payload.c_str());
        if (root == nullptr)
        {
            ESP_LOGE(TAG, "Failed to parse JSON payload");
            return;
        }

        auto type = cJSON_GetObjectItem(root, "type");
        if (type != nullptr && cJSON_IsString(type))
        {
            if (strcmp(type->valuestring, "hello") == 0)
            {
                ParseServerHello(root);
            }
            else if (strcmp(type->valuestring, "goodbye") == 0)
            {
                CloseAudioChannel();
            }
        }

        cJSON_Delete(root); });

    // Connect to MQTT broker
    bool result = mqtt_->Connect();

    if (!result)
    {
        ESP_LOGE(TAG, "Failed to connect to MQTT broker");
        if (report_error)
        {
            SetError(Lang::Strings::CONNECTION_ERROR);
        }
        return false;
    }

    return true;
}

bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (udp_ == nullptr) {
        ESP_LOGE(TAG, "UDP channel is not opened");
        return false;
    }

    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Prepare the UDP packet header
    std::vector<uint8_t> udp_packet;
    udp_packet.reserve(16 + packet->payload.size()); // 16 bytes for header + payload

    // Type field (1 byte)
    udp_packet.push_back(0x01);

    // Flags field (1 byte)
    udp_packet.push_back(0x00);

    // Payload length field (2 bytes, big-endian)
    uint16_t payload_len = packet->payload.size();
    udp_packet.push_back((payload_len >> 8) & 0xFF);
    udp_packet.push_back(payload_len & 0xFF);

    // SSRC field (4 bytes, 0 for now)
    udp_packet.push_back(0x00);
    udp_packet.push_back(0x00);
    udp_packet.push_back(0x00);
    udp_packet.push_back(0x00);

    // Timestamp field (4 bytes, big-endian)
    uint32_t timestamp = packet->timestamp;
    udp_packet.push_back((timestamp >> 24) & 0xFF);
    udp_packet.push_back((timestamp >> 16) & 0xFF);
    udp_packet.push_back((timestamp >> 8) & 0xFF);
    udp_packet.push_back(timestamp & 0xFF);

    // Sequence field (4 bytes, big-endian)
    uint32_t sequence = local_sequence_++;
    udp_packet.push_back((sequence >> 24) & 0xFF);
    udp_packet.push_back((sequence >> 16) & 0xFF);
    udp_packet.push_back((sequence >> 8) & 0xFF);
    udp_packet.push_back(sequence & 0xFF);

    // Encrypt the payload
    size_t encrypted_size = packet->payload.size();
    size_t nc_off = 0;
    uint8_t stream_block[16] = {0};

    // Create nonce with sequence number
    std::vector<uint8_t> nonce = aes_nonce_;
    nonce[12] = (sequence >> 24) & 0xFF;
    nonce[13] = (sequence >> 16) & 0xFF;
    nonce[14] = (sequence >> 8) & 0xFF;
    nonce[15] = sequence & 0xFF;

    // Append encrypted payload
    std::vector<uint8_t> encrypted_payload(encrypted_size);
    int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, encrypted_size, &nc_off, nonce.data(), stream_block, 
                                   (const uint8_t*)packet->payload.data(), encrypted_payload.data());
    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to encrypt audio data, ret: %d", ret);
        return false;
    }

    udp_packet.insert(udp_packet.end(), encrypted_payload.begin(), encrypted_payload.end());

    // Send the packet
    if (!udp_->Send(reinterpret_cast<const char*>(udp_packet.data()), udp_packet.size())) {
        ESP_LOGE(TAG, "Failed to send audio packet");
        return false;
    }

    last_outgoing_time_ = std::chrono::steady_clock::now();
    return true;
}

bool MqttProtocol::OpenAudioChannel()
{
    // Check if MQTT client is ready
    if (mqtt_ == nullptr)
    {
        ESP_LOGE(TAG, "MQTT client not initialized");
        return false;
    }

    // Send hello message to request UDP channel
    std::string hello_message = GetHelloMessage();
    if (!SendText(hello_message))
    {
        ESP_LOGE(TAG, "Failed to send hello message");
        return false;
    }

    // Wait for server hello response with timeout
    EventBits_t bits = xEventGroupWaitBits(
        event_group_handle_,
        MQTT_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,   // Clear bits before returning
        pdFALSE,  // Wait for any bit
        pdMS_TO_TICKS(5000)); // 5 second timeout

    if (!(bits & MQTT_PROTOCOL_SERVER_HELLO_EVENT))
    {
        ESP_LOGE(TAG, "Timeout waiting for server hello response");
        SetError(Lang::Strings::SERVER_TIMEOUT);
        return false;
    }

    // Setup UDP connection
    {
        std::lock_guard<std::mutex> lock(channel_mutex_);

        // Create UDP socket
        auto network = Board::GetInstance().GetNetwork();
        udp_ = network->CreateUdp();

        if (udp_ == nullptr)
        {
            ESP_LOGE(TAG, "Failed to create UDP socket");
            SetError(Lang::Strings::NETWORK_ERROR);
            return false;
        }

        // Connect to UDP server
        if (!udp_->Connect(udp_server_, udp_port_))
        {
            ESP_LOGE(TAG, "Failed to connect to UDP server %s:%d", udp_server_.c_str(), udp_port_);
            SetError(Lang::Strings::NETWORK_ERROR);
            return false;
        }
    }

    // Reset sequence numbers
    local_sequence_ = 0;
    remote_sequence_ = 0;

    ESP_LOGI(TAG, "Audio channel opened successfully");
    return true;
}

std::string MqttProtocol::GetHelloMessage()
{
    cJSON *root = cJSON_CreateObject();

    // Add message type
    cJSON_AddStringToObject(root, "type", "hello");

    // Add device capabilities
    cJSON *capabilities = cJSON_CreateObject();
    cJSON_AddBoolToObject(capabilities, "aec", true);  // AEC support
    cJSON_AddBoolToObject(capabilities, "mcp", true);  // MCP support
    cJSON_AddItemToObject(root, "capabilities", capabilities);

    // Add audio parameters
    cJSON *audio_params = cJSON_CreateObject();
    cJSON_AddStringToObject(audio_params, "format", "opus");  // Assuming OPUS format
    cJSON_AddNumberToObject(audio_params, "sample_rate", 48000);  // Default sample rate
    cJSON_AddNumberToObject(audio_params, "frame_duration", 20);   // Default frame duration in ms
    cJSON_AddItemToObject(root, "audio_params", audio_params);

    // Add device info or other relevant fields
    cJSON *device_info = cJSON_CreateObject();
    cJSON_AddStringToObject(device_info, "device_id", Board::GetInstance().GetDeviceId().c_str());
    cJSON_AddStringToObject(device_info, "version", "1.0");  // Version info
    cJSON_AddItemToObject(root, "device_info", device_info);

    // Convert to string
    char *json_string = cJSON_PrintUnformatted(root);
    std::string result = json_string;

    // Clean up
    free(json_string);
    cJSON_Delete(root);

    return result;
}

void MqttProtocol::ParseServerHello(const cJSON *root)
{
    cJSON *udp = cJSON_GetObjectItem(root, "udp");
    if (udp == nullptr || !cJSON_IsObject(udp))
    {
        ESP_LOGE(TAG, "UDP configuration not found in server hello");
        return;
    }

    udp_server_ = cJSON_GetObjectItem(udp, "server")->valuestring;
    udp_port_ = cJSON_GetObjectItem(udp, "port")->valueint;
    auto key = cJSON_GetObjectItem(udp, "key")->valuestring;
    auto nonce = cJSON_GetObjectItem(udp, "nonce")->valuestring;

    // auto encryption = cJSON_GetObjectItem(udp, "encryption")->valuestring;
    // ESP_LOGI(TAG, "UDP server: %s, port: %d, encryption: %s", udp_server_.c_str(), udp_port_, encryption);
    aes_nonce_ = DecodeHexString(nonce);
    mbedtls_aes_init(&aes_ctx_);
    mbedtls_aes_setkey_enc(&aes_ctx_, (const unsigned char *)DecodeHexString(key).c_str(), 128);
    local_sequence_ = 0;
    remote_sequence_ = 0;

    cJSON *audio = cJSON_GetObjectItem(root, "audio");
    if (audio != nullptr && cJSON_IsObject(audio))
    {
        cJSON *sample_rate = cJSON_GetObjectItem(audio, "sample_rate");
        cJSON *frame_duration = cJSON_GetObjectItem(audio, "frame_duration");

        if (sample_rate != nullptr && cJSON_IsNumber(sample_rate))
        {
            server_sample_rate_ = sample_rate->valuedouble;
        }

        if (frame_duration != nullptr && cJSON_IsNumber(frame_duration))
        {
            server_frame_duration_ = frame_duration->valuedouble;
        }
    }

    session_id_ = cJSON_GetObjectItem(root, "session_id")->valuestring;

    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
}

bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (websocket_ == nullptr || !websocket_->IsConnected())
    {
        return false;
    }

    // Prepare binary data based on protocol version
    std::vector<uint8_t> binary_data;

    if (version_ == 2)
    {
        // Version 2 binary protocol structure
        struct BinaryProtocol2 bp2;
        bp2.version = htons(2);
        bp2.type = htons(1); // Assuming 1 represents audio data type
        bp2.timestamp = htonl(packet->timestamp);
        bp2.payload_size = htonl(packet->payload.size());

        // Allocate memory for header + payload
        binary_data.resize(sizeof(BinaryProtocol2) + packet->payload.size());

        // Copy header
        memcpy(binary_data.data(), &bp2, sizeof(BinaryProtocol2));

        // Copy payload
        memcpy(binary_data.data() + sizeof(BinaryProtocol2), packet->payload.data(), packet->payload.size());
    }
    else if (version_ == 3)
    {
        // Version 3 binary protocol structure
        struct BinaryProtocol3 bp3;
        bp3.type = 1; // Assuming 1 represents audio data type
        bp3.payload_size = htons(packet->payload.size());

        // Allocate memory for header + payload
        binary_data.resize(sizeof(BinaryProtocol3) + packet->payload.size());

        // Copy header
        memcpy(binary_data.data(), &bp3, sizeof(BinaryProtocol3));

        // Copy payload
        memcpy(binary_data.data() + sizeof(BinaryProtocol3), packet->payload.data(), packet->payload.size());
    }
    else
    {
        // Raw payload format for other versions
        binary_data = std::move(packet->payload);
    }

    // Send the binary data
    if (!websocket_->Send(binary_data.data(), binary_data.size(), true))
    {
        ESP_LOGE(TAG, "Failed to send audio data");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    return true;
}

bool WebsocketProtocol::OpenAudioChannel()
{
    // Create WebSocket instance
    websocket_ = std::make_unique<WebSocket>(server_url_);

    if (websocket_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to create WebSocket instance");
        return false;
    }

    // Configure WebSocket headers
    std::map<std::string, std::string> headers;

    // Add authentication header if available
    if (!auth_token_.empty())
    {
        headers["Authorization"] = "Bearer " + auth_token_;
    }

    // Add device information headers
    headers["X-Device-ID"] = device_id_;
    headers["X-Device-Model"] = device_model_;
    headers["X-Device-Version"] = device_version_;
    headers["X-Protocol-Version"] = std::to_string(version_);

    // Set WebSocket headers
    websocket_->SetHeaders(headers);

    // Set up data handler for binary audio packets
    websocket_->SetDataHandler([this](const uint8_t* data, size_t length, bool is_binary) {
        if (!is_binary || data == nullptr || length == 0)
        {
            return;
        }

        // Handle different protocol versions
        if (version_ == 2)
        {
            if (length < sizeof(BinaryProtocol2))
            {
                ESP_LOGW(TAG, "Invalid binary protocol v2 packet size: %zu", length);
                return;
            }

            const BinaryProtocol2* bp2 = reinterpret_cast<const BinaryProtocol2*>(data);

            // Convert from network byte order to host byte order
            uint16_t version = ntohs(bp2->version);
            uint32_t timestamp = ntohl(bp2->timestamp);
            uint32_t payload_size = ntohl(bp2->payload_size);

            // Validate packet structure
            if (length < sizeof(BinaryProtocol2) + payload_size)
            {
                ESP_LOGW(TAG, "Binary protocol v2 packet too short: expected %zu, got %zu", 
                        sizeof(BinaryProtocol2) + payload_size, length);
                return;
            }

            // Create audio packet
            auto packet = std::make_unique<AudioStreamPacket>();
            packet->timestamp = timestamp;
            packet->payload.assign(bp2->payload, bp2->payload + payload_size);

            // Process the audio packet
            ProcessAudioPacket(std::move(packet));
        }
        else if (version_ == 3)
        {
            if (length < sizeof(BinaryProtocol3))
            {
                ESP_LOGW(TAG, "Invalid binary protocol v3 packet size: %zu", length);
                return;
            }

            const BinaryProtocol3* bp3 = reinterpret_cast<const BinaryProtocol3*>(data);

            // Convert from network byte order to host byte order
            uint16_t payload_size = ntohs(bp3->payload_size);

            // Validate packet structure
            if (length < sizeof(BinaryProtocol3) + payload_size)
            {
                ESP_LOGW(TAG, "Binary protocol v3 packet too short: expected %zu, got %zu", 
                        sizeof(BinaryProtocol3) + payload_size, length);
                return;
            }

            // Create audio packet
            auto packet = std::make_unique<AudioStreamPacket>();
            packet->timestamp = 0; // Timestamp not available in v3
            packet->payload.assign(bp3->payload, bp3->payload + payload_size);

            // Process the audio packet
            ProcessAudioPacket(std::move(packet));
        }
        else
        {
            // For other protocol versions or text messages
            auto packet = std::make_unique<AudioStreamPacket>();
            packet->timestamp = 0;
            packet->payload.assign(data, data + length);

            // Process the audio packet
            ProcessAudioPacket(std::move(packet));
        }
    });

    // Connect to WebSocket server
    if (!websocket_->Connect())
    {
        ESP_LOGE(TAG, "Failed to connect to WebSocket server");
        websocket_.reset();
        return false;
    }

    // Send hello message after successful connection
    std::string hello_message = GetHelloMessage();
    if (!SendText(hello_message))
    {
        ESP_LOGE(TAG, "Failed to send hello message");
        websocket_.reset();
        return false;
    }

    // Wait for server hello response (timeout handled elsewhere)
    // This will be handled by the event group mechanism

    return true;
}

std::string WebsocketProtocol::GetHelloMessage()
{
    cJSON *root = cJSON_CreateObject();

    // Add message type
    cJSON_AddStringToObject(root, "type", "hello");

    // Add protocol version
    cJSON_AddNumberToObject(root, "protocol_version", version_);

    // Add features
    cJSON *features = cJSON_CreateObject();
    cJSON_AddFalseToObject(features, "aec");  // Assuming AEC is not supported
    cJSON_AddFalseToObject(features, "mcp");  // Assuming MCP is not supported
    cJSON_AddItemToObject(root, "features", features);

    // Add transport
    cJSON *transport = cJSON_CreateObject();
    cJSON_AddStringToObject(transport, "method", "websocket");
    cJSON_AddItemToObject(root, "transport", transport);

    // Add audio parameters
    cJSON *audio_params = cJSON_CreateObject();
    cJSON_AddStringToObject(audio_params, "format", "pcm_s16le");
    cJSON_AddNumberToObject(audio_params, "sample_rate", server_sample_rate_);
    cJSON_AddNumberToObject(audio_params, "channels", 1);
    cJSON_AddNumberToObject(audio_params, "frame_duration", server_frame_duration_);
    cJSON_AddItemToObject(root, "audio_params", audio_params);

    // Convert to string
    char *json_string = cJSON_Print(root);
    std::string result = json_string;

    // Clean up
    free(json_string);
    cJSON_Delete(root);

    return result;
}

void WebsocketProtocol::ParseServerHello(const cJSON *root)
{
    // Extract server session ID if present
    auto session_id = cJSON_GetObjectItem(root, "session_id");
    if (cJSON_IsString(session_id)) {
        session_id_ = session_id->valuestring;
    }

    // Extract audio parameters
    auto audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (audio_params && cJSON_IsObject(audio_params)) {
        auto sample_rate = cJSON_GetObjectItem(audio_params, "sample_rate");
        if (cJSON_IsNumber(sample_rate)) {
            server_sample_rate_ = sample_rate->valuedouble;
        }

        auto frame_duration = cJSON_GetObjectItem(audio_params, "frame_duration");
        if (cJSON_IsNumber(frame_duration)) {
            server_frame_duration_ = frame_duration->valuedouble;
        }
    }

    // Validate transport type
    auto transport = cJSON_GetObjectItem(root, "transport");
    if (transport && cJSON_IsString(transport)) {
        if (strcmp(transport->valuestring, "websocket") != 0) {
            ESP_LOGW(TAG, "Server reported non-websocket transport: %s", transport->valuestring);
        }
    }

    // Set event flag to indicate server hello received
    xEventGroupSetBits(event_group_handle_, WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT);
}
